from collections import deque, defaultdict

class Solution(object):
    def specialNodes(self, n, edges, x, y, z):
        adj = defaultdict(list)
        for u, v in edges:
            adj[u].append(v)
            adj[v].append(u)

        def bfs(src):
            dist = [-1] * n
            dist[src] = 0
            q = deque([src])
            while q:
                node = q.popleft()
                for nb in adj[node]:
                    if dist[nb] == -1:
                        dist[nb] = dist[node] + 1
                        q.append(nb)
            return dist

        dx = bfs(x)
        dy = bfs(y)
        dz = bfs(z)

        count = 0
        for u in range(n):
            a, b, c = sorted([dx[u], dy[u], dz[u]])
            if a * a + b * b == c * c:
                count += 1
        return count
